const json = $input.first().json;
const raw = (json.chatInput || json.message || json.text || '').trim();
const sid = json.sessionId || 'default';
const sd = $getWorkflowStaticData('global');
if (!sd.pdfTestSessions) sd.pdfTestSessions = {};
const sessions = sd.pdfTestSessions;
const ids = Object.keys(sessions);
if (ids.length >= 10) {
  ids.sort(function(a, b) { return (sessions[a].t || 0) - (sessions[b].t || 0); });
  while (ids.length > 9) delete sessions[ids.shift()];
}
if (/^reset$/i.test(raw)) {
  delete sessions[sid];
  return [{ json: { proceed: 'no', reply: 'Session cleared. Send a company number (e.g. load 06880902) to start a new test.' } }];
}
let lm = raw.match(/^load\s+([A-Za-z0-9]{6,8})$/i);
if (!lm) lm = raw.match(/^(\d{6,8}|[A-Za-z]{2}\d{6})$/);
if (lm) {
  let companyNumber = lm[1].toUpperCase();
  if (/^\d+$/.test(companyNumber)) companyNumber = companyNumber.padStart(8, '0');
  sessions[sid] = { companyNumber: companyNumber, turns: [], t: Date.now() };
  return [{ json: { proceed: 'yes', mode: 'start', companyNumber: companyNumber, feedback: '' } }];
}
const s = sessions[sid];
if (!s || !s.companyNumber) {
  return [{ json: { proceed: 'no', reply: 'No active test session. Start one by sending a company number, e.g. load 06880902' } }];
}
s.t = Date.now();
return [{ json: { proceed: 'yes', mode: 'feedback', companyNumber: s.companyNumber, feedback: raw } }];

const d=$input.first().json;
const f=(d.items||[])[0];
const metaUrl=f&&f.links&&f.links.document_metadata?f.links.document_metadata:null;
const cn=$('Parse & Session').first().json.companyNumber;
return[{json:{metaUrl:metaUrl,filingDate:f?f.date:null,filingType:f?f.type:null,found:metaUrl?'yes':'no',reply:metaUrl?'':'No accounts filing with a document found for company '+cn+'. Check the number and any leading zeros (e.g. 06880902).'}}];

const resp=$input.first().json;
const hdrs=resp.headers||{};
const s3Url=hdrs.location||hdrs.Location||null;
return[{json:{s3Url:s3Url}}];

const images = (($input.first().json) || {}).images || [];
if (images.length === 0) return [{ json: { hasBody: 'no', reply: 'PDF conversion returned no images. Is the converter at 192.168.1.192:8086 running? The download may also have failed - check the execution log.' } }];
const TOKENS_PER_PAGE = 1400; // measured for the converter's A4 page output (~1240x1754); token cost scales with pixel area
const CTX_HEADROOM = 6500; // ~1.5k prompt + up to ~2.4k chat history + response margin
const CTX_CAP = 65536; // ~40 GB total footprint on the 32b model - fits Amelai's GPUs
const CTX_STEP = 8192; // bucketed so similar-sized requests reuse the loaded runner (a num_ctx change forces a model reload)
const maxPages = Math.floor((CTX_CAP - CTX_HEADROOM) / TOKENS_PER_PAGE);
if (images.length > maxPages) return [{ json: { hasBody: 'no', reply: 'This filing has ' + images.length + ' pages; the vision model handles up to ' + maxPages + ' per request at the current context cap.' } }];
const parse = $('Parse & Session').first().json;
const sid = $('When chat message received').first().json.sessionId || 'default';
const sd = $getWorkflowStaticData('global');
const session = (sd.pdfTestSessions || {})[sid] || { turns: [] };
const prompt = 'You are reading pages from UK company accounts filed at Companies House. Look carefully at every page and find these figures.\n\n'
  + 'In UK accounts, tables usually show TWO columns: the LEFT column is the CURRENT YEAR and the RIGHT column is the prior year. Always take figures from the LEFT (current year) column only.\n\n'
  + 'If the accounts show BOTH group/consolidated and individual company figures (for example a "Group" and a "Company" balance sheet, or consolidated and company columns), use the GROUP / CONSOLIDATED figures.\n\n'
  + '1. Annual turnover or revenue (GBP) - current year\n'
  + '2. Average number of employees - single total figure\n'
  + '3. Net assets or total equity (GBP) - current year\n'
  + '4. Profit BEFORE tax (GBP) - current year, negative if a loss\n'
  + '5. Profit AFTER tax (GBP) - current year, negative if a loss\n'
  + '6. Financial year end date\n\n'
  + 'IMPORTANT: If column headings show figures are in thousands (e.g. £000 or £ 000), multiply each figure by 1000 to give the full amount. In UK accounts, figures shown in parentheses e.g. (£45,000) are negative. Always output negative values with a minus sign, not parentheses.\n\n'
  + 'State each figure on its own line in exactly this format:\nTurnover: £2,450,000\nEmployees: 45\nNet assets: £890,000\nProfit before tax: £150,000\nProfit after tax: £123,456\nYear: 2023\n\n'
  + 'If a figure is a loss, write it with a minus sign e.g. Profit after tax: -£45,000\nIf you cannot find a figure, write null for that line. Do not list multiple values for the same field.';
const messages = [];
if (parse.mode === 'feedback') {
  messages.push({ role: 'system', content: 'The user is auditing the figures you extracted from these account pages. When they challenge a figure or ask why, re-examine the attached pages and justify each figure by citing the page number, the statement or note it came from, and the exact row label and column heading you read it from. If you discover you made an error, say so plainly and give the corrected figure. Do not invent page references.' });
}
messages.push({ role: 'user', content: prompt, images: images });
for (const t of (session.turns || [])) messages.push({ role: t.role, content: t.content });
if (parse.mode === 'feedback') messages.push({ role: 'user', content: parse.feedback });
const numCtx = Math.min(CTX_CAP, Math.max(8192, Math.ceil((images.length * TOKENS_PER_PAGE + CTX_HEADROOM) / CTX_STEP) * CTX_STEP));
const model = 'qwen2.5vl:7b'; // flip to qwen2.5vl:32b for A/B testing
const body = JSON.stringify({ model: model, messages: messages, stream: false, options: { num_ctx: numCtx } });
return [{ json: { hasBody: 'yes', ollamaBody: body, pageCount: images.length } }];

const resp = $input.first().json || {};
const content = (resp.message && resp.message.content) || resp.response || null;
if (!content) return [{ json: { output: 'No response from the vision model. Raw: ' + JSON.stringify(resp).substring(0, 500) } }];
const parse = $('Parse & Session').first().json;
const sid = $('When chat message received').first().json.sessionId || 'default';
const sd = $getWorkflowStaticData('global');
const sessions = sd.pdfTestSessions || {};
const session = sessions[sid];
if (session) {
  if (parse.mode === 'feedback') session.turns.push({ role: 'user', content: parse.feedback });
  session.turns.push({ role: 'assistant', content: content });
  if (session.turns.length > 12) session.turns = session.turns.slice(-12);
}
const filing = $('Get Filing URL').first().json;
const pages = $('Build Chat Body').first().json.pageCount;
const header = parse.mode === 'start' ? 'Company ' + parse.companyNumber + ' | accounts filed ' + (filing.filingDate || '?') + ' | ' + pages + ' pages sent to qwen2.5vl:7b\n\n' : '';
const footer = '\n\n---\nReply in plain English to challenge the figures (e.g. Employees is wrong, the accounts say 704 - which page and table did you read it from?). Send another company number to switch, or reset to clear.';
return [{ json: { output: header + content + footer } }];
